class Node:
    def __init__(self, char):
        self.char = char.lower()
        self.left = None
        self.right = None

def insert(root, char):
    if root is None:
        return Node(char)
    if char < root.char:
        root.left = insert(root.left, char)
    elif char > root.char:
        root.right = insert(root.right, char)
    return root

def process_string(s, index=0, root=None):
    if index >= len(s):
        return root
    char = s[index]
    root = insert(root, char)
    return process_string(s, index + 1, root)

